object SqlApiJsonProtocol extends DefaultJsonProtocol {
  implicit val queryRequestFormat = jsonFormat1(QueryRequest)
}

final case class QueryRequest(sql: String)

object SparkSqlApi extends App {
  import SqlApiJsonProtocol._

  implicit val system: ActorSystem                        = ActorSystem("spark-sql-api")
  implicit val materializer: ActorMaterializer            = ActorMaterializer()
  implicit val executionContext: ExecutionContextExecutor = system.dispatcher

  private val spark: SparkSession = SparkSession.builder()
    .appName("UserSQLApi")
    .enableHiveSupport()
    .getOrCreate()

  private val forbiddenPatterns = List(
    "(?i)\\binsert\\b",
    "(?i)\\bupdate\\b",
    "(?i)\\bdelete\\b",
    "(?i)\\bcreate\\b",
    "(?i)\\bdrop\\b",
    "(?i)\\balter\\b",
    "(?i)\\btruncate\\b",
    "(?i)\\bwrite\\b",
    "(?i)\\brefresh\\b",
    "(?i)\\bmsck\\b"
  ).map(_.r)

  private val maxQueryLength = 10000

  private def validateSql(sql: String): Either[String, String] = {
    if (sql.length > maxQueryLength)
      Left("SQL statement too long")
    else if (!sql.trim.toLowerCase.startsWith("select"))
      Left("Only SELECT statements are allowed")
    else if (forbiddenPatterns.exists(_.findFirstIn(sql).isDefined))
      Left("Statement contains forbidden keywords")
    else
      Right(sql)
  }

  private def runQuery(sql: String): Future[String] = Future {
    val df: DataFrame  = spark.sql(sql)
    val json: Array[String] = df.toJSON.collect()
    json.mkString("[", ",", "]")
  }

  private val route: Route =
    path("query") {
      post {
        entity(as[String]) { body =>
          val jsonAst  = body.parseJson
          val request  = jsonAst.convertTo[QueryRequest]
