            case Left(errorMsg) =>
              complete(HttpResponse(StatusCodes.BadRequest, entity = errorMsg))
            case Right(validSql) =>
              onComplete(runQuery(validSql)) {
                case Success(resultJson) =>
                  complete(
                    HttpResponse(
                      entity = HttpEntity(ContentTypes.`application/json`, ByteString(resultJson))
                    )
                  )
                case Failure(ex) =>
                  complete(HttpResponse(InternalServerError, entity = ex.getMessage))
              }
          }
        }
      }
    }

